class Solution:
    def concatenatedBinary(self, n):
        MOD = 10 ** 9 + 7
        result = 0
        bit_len = 0
        for i in range(1, n + 1):
            if i & (i - 1) == 0:
                bit_len += 1
            result = ((result << bit_len) + i) % MOD
        return result

