var concatenatedBinary = function(n) {
    const MOD = 1000000007;
    let result = 0;
    let bitLen = 0;
    let pow = 1;
    for (let i = 1; i <= n; i++) {
        if ((i & (i - 1)) === 0) {
            bitLen++;
            pow *= 2;
        }
        result = (result * pow + i) % MOD;
    }
    return result;
};
